// src/index.js
import * as ReactDOMClient from "react-dom/client";
import ReactDOM, { findDOMNode } from "react-dom";
import App from "./App";
import axios from "axios";

// ▶️ Ajuste para compatibilidade com findDOMNode em libs que ainda dependem do legacy API
ReactDOMClient.findDOMNode = findDOMNode;

// ▶️ Define baseURL para TODO o Axios:
// Em produção, força o domínio do seu Back-end.
// Em desenvolvimento (npm start), deixa vazio para usar o proxy do CRA.
const isProd = process.env.NODE_ENV === "production";
axios.defaults.baseURL = isProd
  ? "https://poliub-novo-ambiente-para-o-backend.up.railway.app"
  : "";

// ▶️ Injeta o token JWT em todas as requisições
axios.interceptors.request.use((config) => {
  const token = localStorage.getItem("token");
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});
axios.interceptors.response.use(
  response => response,
  error => {
    if (error.response?.status === 401) {
      // token expirado ou inválido: desloga e leva ao login
      localStorage.removeItem('token');
      window.location.href = '/#/login';  // se estiver usando HashRouter
    }
    return Promise.reject(error);
  }
);

const container = document.getElementById("root");
const root = ReactDOMClient.createRoot(container);
root.render(<App />);
